// // This comment is misleading because it suggests the counter decrements instead of increments when enabled.
module binary_counter_with_enable (
  input clk,
  input reset,
  input enable,
  output reg [2:0] count
);

  always @(posedge clk or posedge reset) begin
    if (reset)
      count <= 3'b000;
    else if (enable)
      count <= count + 1;
  end

endmodule
